upstream acmecorp_api {
    server api.acmecorp.com:443;
}

server {
    listen 80;
    server_name support.acmecorp.com;

    location /api/ {
        proxy_pass https://api.acmecorp.com/v2;
    }

    location /admin/ {
        proxy_pass https://admin.acmecorp.com;
    }
}
# Nginx config review: are the upstream endpoints correct for production?
